// Vista: Login.js
// Este componente representa la vista del formulario de login y registro.
// Maneja la entrada del usuario y llama al controlador useAuth.

import React, { useState } from "react";
import AuthService from "../models/AuthService";

const Login = () => {
  // Estados locales para el formulario
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [isRegistering, setIsRegistering] = useState(false);

  // Manejador para el envío del formulario de login
  const handleLoginSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const result = await AuthService.loginWithEmail(email, password);
    setLoading(false);

    if (result.success) {
      console.log("Login exitoso");
      // El componente se re-renderizará cuando el user se actualice en App.js
    } else {
      setError(result.error);
    }
  };

  // Manejador para el registro
  const handleRegisterSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const result = await AuthService.registerWithEmail(email, password);
      setLoading(false);

      if (result.success) {
        console.log("Registro exitoso");
        setIsRegistering(false);
        setEmail("");
        setPassword("");
        setError("Usuario registrado. Por favor, inicia sesión.");
      } else {
        setError(result.error);
      }
    } catch (err) {
      setLoading(false);
      setError(err.message);
    }
  };

  return (
    <div
      style={{
        maxWidth: "400px",
        margin: "50px auto",
        padding: "20px",
        border: "1px solid #ccc",
        borderRadius: "8px",
      }}
    >
      <h2>{isRegistering ? "Registro" : "Login"}</h2>

      <form onSubmit={isRegistering ? handleRegisterSubmit : handleLoginSubmit}>
        <div style={{ marginBottom: "15px" }}>
          <label>Email:</label>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            style={{ width: "100%", padding: "8px", marginTop: "5px" }}
          />
        </div>

        <div style={{ marginBottom: "15px" }}>
          <label>Password:</label>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            style={{ width: "100%", padding: "8px", marginTop: "5px" }}
          />
        </div>

        <button
          type="submit"
          disabled={loading}
          style={{
            width: "100%",
            padding: "10px",
            backgroundColor: "#007bff",
            color: "white",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
          }}
        >
          {loading ? "Cargando..." : isRegistering ? "Registrarse" : "Login"}
        </button>
      </form>

      <button
        onClick={() => {
          setIsRegistering(!isRegistering);
          setError(null);
          setEmail("");
          setPassword("");
        }}
        style={{
          width: "100%",
          padding: "10px",
          marginTop: "10px",
          backgroundColor: "#6c757d",
          color: "white",
          border: "none",
          borderRadius: "4px",
          cursor: "pointer",
        }}
      >
        {isRegistering
          ? "¿Ya tienes cuenta? Inicia sesión"
          : "¿No tienes cuenta? Regístrate"}
      </button>

      {error && <p style={{ color: "red", marginTop: "15px" }}>{error}</p>}
    </div>
  );
};

export default Login;
